# Auto-generated by tdd_orchestrator.py — Stage: affine_transform
# Manually fixed for correct Python syntax
"""
TDD Stage: affine_transform
Reader loads gamma and beta tiles. Compute multiplies normalized output by
gamma (ROW broadcast) and adds beta (ROW broadcast). Full layer_norm with affine.
"""

import pytest
import torch
import ttnn


from .layer_norm import layer_norm


def pytorch_reference(torch_input, torch_gamma, torch_beta):
    """PyTorch reference for this stage."""
    return torch.nn.functional.layer_norm(
        torch_input.to(torch.float32),
        [torch_input.shape[-1]],
        weight=torch_gamma.to(torch.float32).squeeze(0),
        bias=torch_beta.to(torch.float32).squeeze(0),
    ).to(torch.bfloat16)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 32, 128), id="1x1x32x128"),
        pytest.param((1, 1, 128, 64), id="1x1x128x64"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((2, 1, 64, 64), id="2x1x64x64"),
    ],
)
def test_affine_transform(device, shape):
    """Verify full layer_norm with affine gamma/beta."""
    torch.manual_seed(42)
    input_shape = shape
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    torch_gamma = torch.randn(1, input_shape[-1], dtype=torch.bfloat16)
    torch_beta = torch.randn(1, input_shape[-1], dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input, torch_gamma, torch_beta)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.TILE_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    gamma_tensor = ttnn.from_torch(
        torch_gamma.unsqueeze(0).unsqueeze(0),
        dtype=ttnn.bfloat16,
        layout=ttnn.TILE_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    beta_tensor = ttnn.from_torch(
        torch_beta.unsqueeze(0).unsqueeze(0),
        dtype=ttnn.bfloat16,
        layout=ttnn.TILE_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm(ttnn_input, gamma_tensor, beta_tensor)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
